    45|function waitForServer(url, retries = 10, delay = 500) {
    46|  return new Promise((resolve, reject) => {
    47|    function attempt(n) {
    48|      http.get(url, (res) => {
    49|        res.resume();
    50|        resolve();
    51|      }).on('error', () => {
    52|        if (n <= 0) reject(new Error('Server did not start'));
    53|        else setTimeout(() => attempt(n - 1), delay);
    54|      });
    55|    }
    56|    attempt(retries);
