  'use strict';

  const searchForm = document.getElementById('search-form');
  const cityInput = document.getElementById('city-input');
  const weatherCard = document.getElementById('weather-card');
  const loading = document.getElementById('loading');
  const errorDiv = document.getElementById('error');
  const presetBtns = document.querySelectorAll('.preset-btn');
  const viewTabs = document.getElementById('view-tabs');
  const tabBtns = document.querySelectorAll('.tab-btn');
  const currentView = document.getElementById('current-weather');
  const forecastView = document.getElementById('forecast-view');
  const forecastContainer = document.getElementById('forecast-container');
  const forecastCards = document.getElementById('forecast-cards');
  const forecastCityName = document.getElementById('forecast-city-name');
  const forecastCountryBadge = document.getElementById('forecast-country-badge');

  const cityNameEl = document.getElementById('city-name');
  const countryBadge = document.getElementById('country-badge');
  const weatherEmoji = document.getElementById('weather-emoji');
  const temperature = document.getElementById('temperature');
  const conditionText = document.getElementById('condition-text');
  const feelsLike = document.getElementById('feels-like');
  const humidity = document.getElementById('humidity');
  const windSpeed = document.getElementById('wind-speed');

  let currentCity = '';
  let currentCountry = '';
  let currentViewMode = 'current'; // 'current' or 'forecast'

  // Day name helper
  function getDayName(dateStr) {
    const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    const d = new Date(dateStr + 'T12:00:00');
    return days[d.getDay()];
  }

  // Format date as "Mon, Jul 12"
  function formatDate(dateStr) {
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const d = new Date(dateStr + 'T12:00:00');
    return months[d.getMonth()] + ' ' + d.getDate();
  }

  // Show/hide helpers
  function showLoading() {
    loading.classList.remove('hidden');
    weatherCard.classList.remove('visible');
    weatherCard.classList.add('hidden');
    forecastContainer.classList.add('hidden');
    errorDiv.classList.add('hidden');
  }

  function showError(msg) {
    errorDiv.textContent = msg;
    errorDiv.classList.remove('hidden');
    loading.classList.add('hidden');
    weatherCard.classList.remove('visible');
    weatherCard.classList.add('hidden');
    forecastContainer.classList.add('hidden');
  }

  function showWeather(data) {
    cityNameEl.textContent = data.city;
    countryBadge.textContent = data.country;
    weatherEmoji.textContent = data.emoji;
    temperature.textContent = data.temperature;
    conditionText.textContent = data.condition;
    feelsLike.textContent = data.feels_like + '°C';
    humidity.textContent = data.humidity + '%';
    windSpeed.textContent = data.wind_speed + ' km/h';

    weatherCard.classList.remove('hidden');
    // Force reflow for animation
    void weatherCard.offsetWidth;
    weatherCard.classList.add('visible');
    loading.classList.add('hidden');
    errorDiv.classList.add('hidden');
  }

  function renderForecast(data) {
    forecastCityName.textContent = data.city;
    forecastCountryBadge.textContent = data.country;

    forecastCards.innerHTML = '';
    data.days.forEach(function (day) {
      const card = document.createElement('div');
      card.className = 'forecast-card';
      card.innerHTML =
        '<div class="forecast-day">' + getDayName(day.date) + '</div>' +
        '<div class="forecast-date">' + formatDate(day.date) + '</div>' +
        '<div class="forecast-emoji">' + day.emoji + '</div>' +
        '<div class="forecast-condition">' + day.condition + '</div>' +
        '<div class="forecast-temps">' +
          '<span class="forecast-high">' + day.temp_max + '°</span>' +
          '<span class="forecast-low">' + day.temp_min + '°</span>' +
        '</div>' +
        '<div class="forecast-details-row">' +
          '<span class="forecast-detail">💧 ' + day.precipitation + 'mm</span>' +
          '<span class="forecast-detail">💨 ' + Math.round(day.wind_max) + ' km/h</span>' +
        '</div>';
      forecastCards.appendChild(card);
    });

    forecastContainer.classList.remove('hidden');
    loading.classList.add('hidden');
    errorDiv.classList.add('hidden');
  }

  async function fetchWeather(city) {
    if (!city || !city.trim()) return;

    const trimmed = city.trim();
    showLoading();

    try {
      const res = await fetch('/api/weather?city=' + encodeURIComponent(trimmed));

      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        throw new Error(body.error || 'Failed to fetch weather data');
      }

      const data = await res.json();
      currentCity = data.city;
      currentCountry = data.country;
      showWeather(data);
      showView('current');
      viewTabs.classList.remove('hidden');
    } catch (err) {
      showError(err.message || 'Something went wrong. Please try again.');
    }
  }

  async function fetchForecast(city) {
    if (!city || !city.trim()) return;

    const trimmed = city.trim();
    showLoading();

    try {
      const res = await fetch('/api/forecast?city=' + encodeURIComponent(trimmed));

      if (!res.ok) {
        const body = await res.json().catch(() => ({}));
        throw new Error(body.error || 'Failed to fetch forecast data');
      }

      const data = await res.json();
      currentCity = data.city;
      currentCountry = data.country;
      renderForecast(data);
      showView('forecast');
    } catch (err) {
      showError(err.message || 'Something went wrong. Please try again.');
    }
  }

  function showView(mode) {
    currentViewMode = mode;
    tabBtns.forEach(function (btn) {
      btn.classList.toggle('active', btn.getAttribute('data-view') === mode);
    });

    if (mode === 'current') {
      currentView.classList.remove('hidden');
      forecastView.classList.add('hidden');
    } else {
      currentView.classList.add('hidden');
      forecastView.classList.remove('hidden');
    }
  }

  function loadDataForCurrentView() {
    if (!currentCity) return;
    if (currentViewMode === 'current') {
      fetchWeather(currentCity);
    } else {
      fetchForecast(currentCity);
    }
  }

  // Tab switching
  tabBtns.forEach(function (btn) {
    btn.addEventListener('click', function () {
      const view = btn.getAttribute('data-view');
      if (view === currentViewMode) return;
      showView(view);
      loadDataForCurrentView();
    });
  });

  // Form submit
  searchForm.addEventListener('submit', function (e) {
    e.preventDefault();
    currentCity = cityInput.value.trim();
    fetchWeather(cityInput.value);
  });

  // Preset city buttons
  presetBtns.forEach(function (btn) {
    btn.addEventListener('click', function () {
      const city = btn.getAttribute('data-city');
      cityInput.value = city;
      fetchWeather(city);
    });
  });

  // Auto-focus on load
  cityInput.focus();
})();
